  @protected
  void sse_encode_math_layout(MathLayout self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_f_64(self.width, serializer);
    sse_encode_f_64(self.height, serializer);
    sse_encode_f_64(self.depth, serializer);
    sse_encode_list_math_node(self.nodes, serializer);
  }

  @protected
  void sse_encode_math_node(MathNode self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case MathNode_Glyph(
        codepoint: final codepoint,
        x: final x,
        y: final y,
        fontName: final fontName,
        scale: final scale,
        color: final color,
        nodeId: final nodeId,
      ):
        sse_encode_i_32(0, serializer);
        sse_encode_u_32(codepoint, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
        sse_encode_String(fontName, serializer);
        sse_encode_f_64(scale, serializer);
        sse_encode_opt_String(color, serializer);
        sse_encode_opt_box_autoadd_u_32(nodeId, serializer);
      case MathNode_Rule(
        x: final x,
        y: final y,
        width: final width,
        height: final height,
        color: final color,
        nodeId: final nodeId,
      ):
        sse_encode_i_32(1, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_opt_String(color, serializer);
        sse_encode_opt_box_autoadd_u_32(nodeId, serializer);
      case MathNode_SvgPath(
        x: final x,
        y: final y,
        width: final width,
        height: final height,
        viewBoxX: final viewBoxX,
        viewBoxY: final viewBoxY,
        viewBoxWidth: final viewBoxWidth,
        viewBoxHeight: final viewBoxHeight,
        commands: final commands,
        nodeId: final nodeId,
      ):
        sse_encode_i_32(2, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_f_64(viewBoxX, serializer);
        sse_encode_f_64(viewBoxY, serializer);
        sse_encode_f_64(viewBoxWidth, serializer);
        sse_encode_f_64(viewBoxHeight, serializer);
        sse_encode_list_path_command(commands, serializer);
        sse_encode_opt_box_autoadd_u_32(nodeId, serializer);
    }
  }

  @protected
  void sse_encode_node_layout(NodeLayout self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case NodeLayout_Leaf(
        nodeId: final nodeId,
        glyphs: final glyphs,
        width: final width,
        height: final height,
        depth: final depth,
      ):
        sse_encode_i_32(0, serializer);
        sse_encode_u_32(nodeId, serializer);
        sse_encode_list_math_node(glyphs, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_f_64(depth, serializer);
      case NodeLayout_Command(
        nodeId: final nodeId,
        kind: final kind,
        width: final width,
        height: final height,
        depth: final depth,
        childBlocks: final childBlocks,
        decorations: final decorations,
      ):
        sse_encode_i_32(1, serializer);
        sse_encode_u_32(nodeId, serializer);
        sse_encode_box_autoadd_command_layout_kind(kind, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_f_64(depth, serializer);
        sse_encode_list_block_layout(childBlocks, serializer);
        sse_encode_list_math_node(decorations, serializer);
    }
  }

  @protected
  void sse_encode_opt_String(String? self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs

    sse_encode_bool(self != null, serializer);
    if (self != null) {
      sse_encode_String(self, serializer);
    }
