  @protected
  void sse_encode_path_command(PathCommand self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case PathCommand_MoveTo(x: final x, y: final y):
        sse_encode_i_32(0, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
      case PathCommand_LineTo(x: final x, y: final y):
        sse_encode_i_32(1, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
      case PathCommand_CubicTo(
        x1: final x1,
        y1: final y1,
        x2: final x2,
        y2: final y2,
        x: final x,
        y: final y,
      ):
        sse_encode_i_32(2, serializer);
        sse_encode_f_64(x1, serializer);
        sse_encode_f_64(y1, serializer);
        sse_encode_f_64(x2, serializer);
        sse_encode_f_64(y2, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
      case PathCommand_QuadTo(
        x1: final x1,
        y1: final y1,
        x: final x,
        y: final y,
      ):
        sse_encode_i_32(3, serializer);
        sse_encode_f_64(x1, serializer);
        sse_encode_f_64(y1, serializer);
        sse_encode_f_64(x, serializer);
        sse_encode_f_64(y, serializer);
      case PathCommand_Close():
        sse_encode_i_32(4, serializer);
    }
  }

